import styles from "./index.module.css";
import { useRouter } from "next/router";
import { useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { setTokenIsThere } from "@/config/redux/reducer/authReducer";
import { BASE_URL } from "@/config";

export default function DashboardLayout({ children }) {
  const authState = useSelector((state) => state.auth);
  const router = useRouter();
  const dispatch = useDispatch();

  useEffect(() => {
    if (localStorage.getItem("token")) {
      dispatch(setTokenIsThere());
    } else {
      router.push("/login");
    }
  }, [dispatch, router]);

  const navItems = [
    {
      label: "Scroll",
      path: "/dashboard",
      icon: (
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" width="20" height="20">
          <path strokeLinecap="round" strokeLinejoin="round" d="m2.25 12 8.954-8.955c.44-.439 1.152-.439 1.591 0L21.75 12M4.5 9.75v10.125c0 .621.504 1.125 1.125 1.125H9.75v-4.875c0-.621.504-1.125 1.125-1.125h2.25c.621 0 1.125.504 1.125 1.125V21h4.125c.621 0 1.125-.504 1.125-1.125V9.75M8.25 21h8.25" />
        </svg>
      ),
    },
    {
      label: "Discover",
      path: "/discover",
      icon: (
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" width="20" height="20">
          <path strokeLinecap="round" strokeLinejoin="round" d="m21 21-5.197-5.197m0 0A7.5 7.5 0 1 0 5.196 5.196a7.5 7.5 0 0 0 10.607 10.607Z" />
        </svg>
      ),
    },
    {
      label: "My connections",
      path: "/my_connections",
      icon: (
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" width="20" height="20">
          <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 6a3.75 3.75 0 1 1-7.5 0 3.75 3.75 0 0 1 7.5 0ZM4.501 20.118a7.5 7.5 0 0 1 14.998 0A17.933 17.933 0 0 1 12 21.75c-2.676 0-5.216-.584-7.499-1.632Z" />
        </svg>
      ),
    },
  ];

  return (
    <div className={styles.shell}>
      {/* ── Left sidebar ── */}
      <aside className={styles.sidebar}>
        {/* <div className={styles.logo}>Connectify</div> */}
        {navItems.map((item) => (
          <button
            key={item.path}
            className={`${styles.navItem} ${router.pathname === item.path ? styles.active : ""}`}
            onClick={() => router.push(item.path)}
          >
            {item.icon}
            <span>{item.label}</span>
          </button>
        ))}
      </aside>

      {/* ── Main feed ── */}
      <main className={styles.feed}>{children}</main>

      {/* ── Right panel ── */}
      <aside className={styles.rightPanel}>
        <p className={styles.panelTitle}>Top profiles</p>

        {authState.all_profiles_fetched && authState.all_users?.length > 0 ? (
          authState.all_users.map((profile) => (
            <div
              key={profile._id}
              className={styles.profileRow}
              onClick={() => router.push(`/view_profile/${profile.userId.username}`)}
            >
              <img
                className={styles.profileAvatar}
                src={`${BASE_URL}/${profile.userId.profilePicture}`}
                alt={profile.userId.name}
              />
              <div className={styles.profileInfo}>
                <p className={styles.profileName}>{profile.userId.name}</p>
                <p className={styles.profileHandle}>@{profile.userId.username}</p>
              </div>
            </div>
          ))
        ) : (
          <p className={styles.emptyProfiles}>No profiles yet.</p>
        )}
      </aside>
    </div>
  );
}